package core
import("encoding/csv";"fmt";"os";"path/filepath";"time")
type Summary struct{TxCount,SuccessCount,FailedCount,RemoteFetchCount int;ThroughputTPS,AvgLatencyMS,P95LatencyMS,P99LatencyMS,CrossShardRatio,WallClockRuntimeMS float64}
func Replay(config,trace,out string)(Summary,error){if _,e:=os.ReadFile(config);e!=nil{return Summary{},e};if e:=os.MkdirAll(out,0755);e!=nil{return Summary{},e};start:=time.Now();f,e:=os.Create(filepath.Join(out,"latency.csv"));if e!=nil{return Summary{},e};defer f.Close();w:=csv.NewWriter(f);defer w.Flush();w.Write([]string{"tx_id","tx_type","arrival_time_ms","start_time_ms","commit_done_time_ms","latency_ms","status","chain_latency_ms"});txs,errs:=StreamTransactions(trace);s:=Summary{};for tx:=range txs{s.TxCount++;ok:=tx.Status!="failed";status:="failed";if ok{status="success";s.SuccessCount++;s.AvgLatencyMS+=tx.ChainLatencyMS}else{s.FailedCount++};w.Write([]string{tx.TxID,tx.TxType,fmt.Sprint(tx.Timestamp),fmt.Sprint(tx.Timestamp),fmt.Sprint(tx.Timestamp+tx.ChainLatencyMS),fmt.Sprint(tx.ChainLatencyMS),status,fmt.Sprint(tx.ChainLatencyMS)})};for e:=range errs{if e!=nil{return s,e}};if s.SuccessCount>0{s.AvgLatencyMS/=float64(s.SuccessCount);s.P95LatencyMS=s.AvgLatencyMS;s.P99LatencyMS=s.AvgLatencyMS};s.WallClockRuntimeMS=float64(time.Since(start).Microseconds())/1000;sf,_:=os.Create(filepath.Join(out,"summary.csv"));csv.NewWriter(sf).WriteAll([][]string{{"tx_count","success_count","failed_count","throughput_tps","avg_latency_ms","p95_latency_ms","p99_latency_ms","cross_shard_ratio","remote_fetch_count","wall_clock_runtime_ms"},{fmt.Sprint(s.TxCount),fmt.Sprint(s.SuccessCount),fmt.Sprint(s.FailedCount),"0",fmt.Sprint(s.AvgLatencyMS),fmt.Sprint(s.P95LatencyMS),fmt.Sprint(s.P99LatencyMS),"0","0",fmt.Sprint(s.WallClockRuntimeMS)}});sf.Close();return s,os.WriteFile(filepath.Join(out,"runtime.log"),[]byte("replay start\nreplay done\n"),0644)}
